# ------------------------------------------------------------
# Utility helpers
# ------------------------------------------------------------
def safe_float(value):
    if value is None or value == "":
        return np.nan
    try:
        return float(value)
    except Exception:
        return np.nan


def validate_positive(name: str, value: float):
    if pd.isna(value) or value <= 0:
        raise ValueError(f"{name} must be greater than 0.")


def density_term_hardin(e: float, a: float) -> float:
    if (1 + e) <= 0:
        raise ValueError("1 + e must be greater than 0.")
    return ((a - e) ** 2) / (1 + e)


def density_term_inv_1plus_e(e: float, x: float) -> float:
    if (1 + e) <= 0:
        raise ValueError("1 + e must be greater than 0.")
    return 1.0 / ((1 + e) ** x)


def density_term_inv_e(e: float, x: float) -> float:
    validate_positive("Void ratio e", e)
    return 1.0 / (e ** x)


def calculate_r2(y_true: np.ndarray, y_pred: np.ndarray) -> float:
    mask = (~np.isnan(y_true)) & (~np.isnan(y_pred))
    y_true = y_true[mask]
    y_pred = y_pred[mask]
    if len(y_true) < 2:
        return np.nan
    ss_res = np.sum((y_true - y_pred) ** 2)
    ss_tot = np.sum((y_true - np.mean(y_true)) ** 2)
    if ss_tot == 0:
        return np.nan
    return 1 - (ss_res / ss_tot)


def calculate_rmse(y_true: np.ndarray, y_pred: np.ndarray) -> float:
    mask = (~np.isnan(y_true)) & (~np.isnan(y_pred))
    y_true = y_true[mask]
    y_pred = y_pred[mask]
    if len(y_true) == 0:
        return np.nan
    return float(np.sqrt(np.mean((y_true - y_pred) ** 2)))


def calculate_mae(y_true: np.ndarray, y_pred: np.ndarray) -> float:
    mask = (~np.isnan(y_true)) & (~np.isnan(y_pred))
    y_true = y_true[mask]
    y_pred = y_pred[mask]
    if len(y_true) == 0:
        return np.nan
    return float(np.mean(np.abs(y_true - y_pred)))


def calculate_mse(y_true: np.ndarray, y_pred: np.ndarray) -> float:
    mask = (~np.isnan(y_true)) & (~np.isnan(y_pred))
    y_true = y_true[mask]
    y_pred = y_pred[mask]
    if len(y_true) == 0:
        return np.nan
    return float(np.mean((y_true - y_pred) ** 2))


def calculate_mape(y_true: np.ndarray, y_pred: np.ndarray) -> float:
    mask = (~np.isnan(y_true)) & (~np.isnan(y_pred)) & (y_true != 0)
    y_true = y_true[mask]
    y_pred = y_pred[mask]
    if len(y_true) == 0:
        return np.nan
    return float(np.mean(np.abs((y_true - y_pred) / y_true)) * 100)


def calculate_vaf(y_true: np.ndarray, y_pred: np.ndarray) -> float:
    mask = (~np.isnan(y_true)) & (~np.isnan(y_pred))
    y_true = y_true[mask]
    y_pred = y_pred[mask]
    if len(y_true) < 2:
        return np.nan
    var_err = np.var(y_true - y_pred, ddof=1)
    var_true = np.var(y_true, ddof=1)
    if var_true == 0:
        return np.nan
    return float((1 - var_err / var_true) * 100)


def calculate_a10(y_true: np.ndarray, y_pred: np.ndarray) -> float:
    mask = (~np.isnan(y_true)) & (~np.isnan(y_pred)) & (y_true != 0)
    y_true = y_true[mask]
    y_pred = y_pred[mask]
    if len(y_true) == 0:
        return np.nan
    rel_error = np.abs((y_pred - y_true) / y_true)
    return float(np.mean(rel_error <= 0.10) * 100)


def build_statistics_table(result_df: pd.DataFrame, selected_models: List[str], display_names: Dict[str, str]) -> pd.DataFrame:
    if "Gmax" not in result_df.columns:
        return pd.DataFrame()

    y_true = result_df["Gmax"].to_numpy(dtype=float)
    rows = []
    for model_key in selected_models:
        pred_col = f"Gmax_{display_names[model_key]}"
        if pred_col not in result_df.columns:
            continue
        y_pred = result_df[pred_col].to_numpy(dtype=float)
        rows.append({
            "Model": display_names[model_key],
            "R^2": calculate_r2(y_true, y_pred),
            "RMSE": calculate_rmse(y_true, y_pred),
            "MAE": calculate_mae(y_true, y_pred),
            "MSE": calculate_mse(y_true, y_pred),
            "MAPE (%)": calculate_mape(y_true, y_pred),
            "VAF (%)": calculate_vaf(y_true, y_pred),
            "a10 (%)": calculate_a10(y_true, y_pred),
            "Mean predicted Gmax (MPa)": np.nanmean(y_pred),
            "Min predicted Gmax (MPa)": np.nanmin(y_pred),
            "Max predicted Gmax (MPa)": np.nanmax(y_pred),
        })
    return pd.DataFrame(rows)


def dataframe_to_excel_bytes(pred_df: pd.DataFrame, stats_df: pd.DataFrame) -> bytes:
    output = io.BytesIO()
    with pd.ExcelWriter(output, engine="openpyxl") as writer:
        pred_df.to_excel(writer, index=False, sheet_name="Predictions")
        if not stats_df.empty:
            stats_df.to_excel(writer, index=False, sheet_name="Statistical_Comparison")
    return output.getvalue()


def plot_predicted_measured_all_models(result_df: pd.DataFrame, selected_models: List[str], display_names: Dict[str, str]):
    if "Gmax" not in result_df.columns:
        return None

    y_true = result_df["Gmax"].to_numpy(dtype=float)
    marker_styles = ["o", "s", "^", "D", "v", "P", "X", "*", "<", ">"]

    fig, ax = plt.subplots(figsize=(8.5, 7))
    all_values = []

    for idx, model_key in enumerate(selected_models):
        pred_col = f"Gmax_{display_names[model_key]}"
        if pred_col not in result_df.columns:
            continue

        y_pred = result_df[pred_col].to_numpy(dtype=float)
        mask = (~np.isnan(y_true)) & (~np.isnan(y_pred))
        if np.sum(mask) == 0:
            continue

        r2 = calculate_r2(y_true[mask], y_pred[mask])
        ax.scatter(
            y_true[mask],
            y_pred[mask],
            label=f"{display_names[model_key]} (R²={r2:.3f})" if not np.isnan(r2) else display_names[model_key],
            marker=marker_styles[idx % len(marker_styles)],
            alpha=0.85,
            s=55,
        )
        all_values.extend(y_true[mask].tolist())
        all_values.extend(y_pred[mask].tolist())

    if len(all_values) == 0:
        plt.close(fig)
        return None

    min_val = min(all_values)
    max_val = max(all_values)
    pad = 0.05 * (max_val - min_val) if max_val > min_val else 1.0
    low = min_val - pad
    high = max_val + pad

    ax.plot([low, high], [low, high], linestyle="--", linewidth=1.5, label="1:1 line")
    ax.set_xlim(low, high)
    ax.set_ylim(low, high)
    ax.set_xlabel("Measured Gmax (MPa)")
    ax.set_ylabel("Predicted Gmax (MPa)")
    ax.set_title("Predicted vs Measured Gmax")
    ax.legend(fontsize=9)
    ax.grid(True, alpha=0.3)

    return fig


# ------------------------------------------------------------
# Model definitions
# ------------------------------------------------------------
@dataclass
class ModelSpec:
    key: str
    display_name: str
    reference: str
    soil_type: str
    required_inputs: List[str]
    formula_label: str
    output_unit: str
    predictor: Callable[[Dict[str, float]], float]
    notes: str = ""


def predict_hardin_black_1(values: Dict[str, float]) -> float:
    e = values["e"]
    p = values["P"]
    validate_positive("Void ratio e", e)
    validate_positive("Confining pressure P", p)
    A = 6.9
    a = 2.17
    n = 0.5
    return A * density_term_hardin(e, a) * (p ** n)


def predict_hardin_black_2(values: Dict[str, float]) -> float:
    e = values["e"]
    p = values["P"]
    validate_positive("Void ratio e", e)
    validate_positive("Confining pressure P", p)
    A = 3.2
    a = 2.97
    n = 0.5
    return A * density_term_hardin(e, a) * (p ** n)


def predict_oztoprak_bolton(values: Dict[str, float]) -> float:
    e = values["e"]
    p = values["P"]
    pa = values["Pa"]
    validate_positive("Void ratio e", e)
    validate_positive("Confining pressure P", p)
    validate_positive("Atmospheric pressure Pa", pa)
    A = 576.0
    x = 3.0
    n = 0.49
    return A * density_term_inv_1plus_e(e, x) * ((p / pa) ** n)


def predict_menq(values: Dict[str, float]) -> float:
    e = values["e"]
    p = values["P"]
    pa = values["Pa"]
    cu = values["Cu"]
    d50 = values["d50"]
    validate_positive("Void ratio e", e)
    validate_positive("Confining pressure P", p)
    validate_positive("Atmospheric pressure Pa", pa)
    validate_positive("Coefficient of uniformity Cu", cu)
    validate_positive("Median grain size d50", d50)
    A = 67.1 * (cu ** -0.20)
    x = 1.0 + ((d50 / 20.0) ** 0.75)
    n = 0.48 * (cu ** 0.09)
    return A * density_term_inv_e(e, x) * ((p / pa) ** n)


def predict_senetakis_madhusudhan(values: Dict[str, float]) -> float:
    e = values["e"]
    p = values["P"]
    pa = values["Pa"]
    cu = values["Cu"]
    validate_positive("Void ratio e", e)
    validate_positive("Confining pressure P", p)
    validate_positive("Atmospheric pressure Pa", pa)
    validate_positive("Coefficient of uniformity Cu", cu)
    A = 81.8 - 3.36 * cu
    x = 1.3
    n = 0.485 * (cu ** 0.13)
    return A * density_term_inv_e(e, x) * ((p / pa) ** n)


def predict_liu_2021(values: Dict[str, float]) -> float:
    e = values["e"]
    p = values["P"]
    pa = values["Pa"]
    cu = values["Cu"]
    d50 = values["d50"]
    validate_positive("Void ratio e", e)
    validate_positive("Confining pressure P", p)
    validate_positive("Atmospheric pressure Pa", pa)
    validate_positive("Coefficient of uniformity Cu", cu)
    validate_positive("Median grain size d50", d50)
    A = 77.46 * (cu ** -0.456) * (d50 ** 0.152)
    x = 1.3
    n = 0.466 * (cu ** 0.094)
    return A * density_term_inv_e(e, x) * ((p / pa) ** n)


def predict_wichtmann_triantafyllidis(values: Dict[str, float]) -> float:
    e = values["e"]
    p = values["P"]
    pa = values["Pa"]
    cu = values["Cu"]
    validate_positive("Void ratio e", e)
    validate_positive("Confining pressure P", p)
    validate_positive("Atmospheric pressure Pa", pa)
    validate_positive("Coefficient of uniformity Cu", cu)

    A = 1563.0 + 3.13 * (cu ** 2.98)
    a = 1.94 * math.exp(-0.066 * cu)
    n = 0.40 * (cu ** 0.18)
    gmax_kpa = A * density_term_hardin(e, a) * (pa ** (1.0 - n)) * (p ** n)
    return gmax_kpa / 1000.0


MODELS: Dict[str, ModelSpec] = {
    "HB1": ModelSpec(
        key="HB1",
        display_name="Hardin and Black (1966)-1",
        reference="Hardin and Black (1966)-1",
        soil_type="Ottawa sand",
        required_inputs=["e", "P"],
        formula_label="Gmax = A * ((a - e)^2 / (1 + e)) * P^n",
        output_unit="MPa",
        predictor=predict_hardin_black_1,
        notes="Constants: A=6.9, a=2.17, n=0.5",
    ),
    "HB2": ModelSpec(
        key="HB2",
        display_name="Hardin and Black (1966)-2",
        reference="Hardin and Black (1966)-2",
        soil_type="Crushed quartz sand",
        required_inputs=["e", "P"],
        formula_label="Gmax = A * ((a - e)^2 / (1 + e)) * P^n",
        output_unit="MPa",
        predictor=predict_hardin_black_2,
        notes="Constants: A=3.2, a=2.97, n=0.5",
    ),
    "OB2013": ModelSpec(
        key="OB2013",
        display_name="Oztoprak and Bolton (2013)",
        reference="Oztoprak and Bolton (2013)",
        soil_type="Silt, sand, and gravel",
        required_inputs=["e", "P", "Pa"],
        formula_label="Gmax = A * (1 / (1 + e)^x) * (P / Pa)^n",
        output_unit="MPa",
        predictor=predict_oztoprak_bolton,
        notes="Constants: A=576, x=3, n=0.49",
    ),
    "MENQ2003": ModelSpec(
        key="MENQ2003",
        display_name="Menq (2003)",
        reference="Menq (2003)",
        soil_type="Sand and gravel",
        required_inputs=["e", "P", "Pa", "Cu", "d50"],
        formula_label="Gmax = A * (1 / e^x) * (P / Pa)^n",
        output_unit="MPa",
        predictor=predict_menq,
        notes="A=67.1*Cu^-0.20; x=1+(d50/20)^0.75; n=0.48*Cu^0.09",
    ),
    "SM2015": ModelSpec(
        key="SM2015",
        display_name="Senetakis and Madhusudhan (2015)",
        reference="Senetakis and Madhusudhan (2015)",
        soil_type="Coarse sand and fine gravel",
        required_inputs=["e", "P", "Pa", "Cu"],
        formula_label="Gmax = A * (1 / e^x) * (P / Pa)^n",
        output_unit="MPa",
        predictor=predict_senetakis_madhusudhan,
        notes="A=81.8 - 3.36*Cu; x=1.3; n=0.485*Cu^0.13",
    ),
    "LIU2021": ModelSpec(
        key="LIU2021",
        display_name="Liu et al. (2021)",
        reference="Liu et al. (2021)",
        soil_type="Sand and gravel",
        required_inputs=["e", "P", "Pa", "Cu", "d50"],
        formula_label="Gmax = A * (1 / e^x) * (P / Pa)^n",
        output_unit="MPa",
        predictor=predict_liu_2021,
        notes="A=77.46*Cu^-0.456*d50^0.152; x=1.3; n=0.466*Cu^0.094",
    ),
    "WT2009": ModelSpec(
        key="WT2009",
        display_name="Wichtmann and Triantafyllidis (2009)",
        reference="Wichtmann and Triantafyllidis (2009)",
        soil_type="Quartz sand and gravel",
        required_inputs=["e", "P", "Pa", "Cu"],
        formula_label="Gmax = A * ((a - e)^2 / (1 + e)) * Pa^(1-n) * P^n",
        output_unit="MPa",
        predictor=predict_wichtmann_triantafyllidis,
        notes="A=1563+3.13*Cu^2.98; a=1.94*exp(-0.066*Cu); n=0.40*Cu^0.18; raw output converted from kPa to MPa",
    ),
}

INPUT_LABELS = {
    "e": "Void ratio, e (–)",
    "P": "Effective confining pressure, P (kPa)",
    "Pa": "Atmospheric pressure, Pa (kPa)",
    "Cu": "Coefficient of uniformity, Cu (–)",
    "d50": "Median grain size, d50",
}


def compute_model(model_key: str, values: Dict[str, float]) -> float:
    spec = MODELS[model_key]
    return spec.predictor(values)


def standardize_batch_dataframe(df: pd.DataFrame, batch_pa_constant: float) -> pd.DataFrame:
    data = df.copy()
    rename_map = {}
    for col in data.columns:
        c = str(col).strip()
        lc = c.lower()
        if lc == "p":
            rename_map[col] = "P"
        elif lc == "pa":
            rename_map[col] = "Pa"
        elif lc == "cu":
            rename_map[col] = "Cu"
        elif lc == "d50":
            rename_map[col] = "d50"
        elif lc == "e":
            rename_map[col] = "e"
        elif lc == "gmax":
            rename_map[col] = "Gmax"

    data = data.rename(columns=rename_map)

    for col in ["e", "P", "Pa", "Cu", "d50", "Gmax"]:
        if col not in data.columns:
            data[col] = np.nan

    data["Pa"] = batch_pa_constant
    return data


def compute_all_selected(df: pd.DataFrame, selected_models: List[str]) -> Tuple[pd.DataFrame, pd.DataFrame]:
    result_df = df.copy()
    display_names = {k: MODELS[k].display_name for k in selected_models}

    for model_key in selected_models:
        spec = MODELS[model_key]
        output_col = f"Gmax_{spec.display_name}"
        outputs = []
        errors = []

        for _, row in result_df.iterrows():
            try:
                vals = {k: safe_float(row.get(k, np.nan)) for k in INPUT_LABELS.keys()}
                pred = compute_model(model_key, vals)
                outputs.append(pred)
                errors.append("")
            except Exception as exc:
                outputs.append(np.nan)
                errors.append(str(exc))

        result_df[output_col] = outputs
        error_col = f"Error_{spec.display_name}"
        result_df[error_col] = errors

    stats_df = build_statistics_table(result_df, selected_models, display_names)
    return result_df, stats_df


