# ------------------------------------------------------------
# Single prediction
# ------------------------------------------------------------
if mode == "Single prediction":
    st.subheader("Single prediction")

    single_model = st.selectbox(
        "Choose model",
        options=selected_models,
        format_func=lambda k: MODELS[k].display_name,
    )
    spec = MODELS[single_model]

    col1, col2, col3 = st.columns(3)
    field_columns = [col1, col2, col3]

    input_values = {}
    for idx, field in enumerate(spec.required_inputs):
        col = field_columns[idx % 3]
        default_value = default_pa if field == "Pa" else 0.0
        input_values[field] = col.number_input(
            INPUT_LABELS[field],
            min_value=0.0,
            value=float(default_value),
            step=0.001 if field in ["e", "Cu", "d50"] else 1.0,
            format="%.6f",
        )

    if st.button("Run single prediction", type="primary"):
        try:
            prediction = compute_model(single_model, input_values)

            st.success("Prediction completed successfully.")
            c1, c2 = st.columns([1, 1])
            with c1:
                st.metric("Predicted Gmax", f"{prediction:,.4f} {spec.output_unit}")
            with c2:
                st.write(f"**Model:** {spec.display_name}")
                st.write(f"**Reference:** {spec.reference}")
                st.write(f"**Soil type:** {spec.soil_type}")

            st.markdown("#### Equation form")
            st.code(spec.formula_label, language="text")

            st.markdown("#### Notes")
            st.write(spec.notes)

            input_table = pd.DataFrame(
                {
                    "Input": list(input_values.keys()),
                    "Value": list(input_values.values()),
                }
            )
            st.markdown("#### Inputs used")
            st.dataframe(input_table, use_container_width=True)

        except Exception as exc:
            st.error(f"Prediction failed: {exc}")


