    template_df = pd.DataFrame(
        {
            "e": [0.677609],
            "p": [50.0],
            "Cu": [1.5],
            "pa": [default_pa],
            "d50": [2.5],
            "Gmax": [89.830508],
        }
    )
    template_bytes = dataframe_to_excel_bytes(template_df, pd.DataFrame())

    st.download_button(
        "Download Excel template",
        data=template_bytes,
        file_name="gmax_empirical_template.xlsx",
        mime="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
    )

    uploaded_file = st.file_uploader(
        "Upload Excel or CSV file",
        type=["xlsx", "xls", "csv"],
        accept_multiple_files=False,
    )

    if uploaded_file is not None:
        try:
            if uploaded_file.name.lower().endswith(".csv"):
                df = pd.read_csv(uploaded_file)
            else:
                df = pd.read_excel(uploaded_file)

            df = standardize_batch_dataframe(df, default_pa)

            st.markdown("#### Uploaded data preview")
            st.dataframe(df.head(20), use_container_width=True)

            if st.button("Run batch prediction", type="primary"):
                result_df, stats_df = compute_all_selected(df, selected_models)

                st.success("Batch prediction completed successfully.")

                st.markdown("#### Prediction results")

                input_cols = ["e", "P", "Pa", "Cu", "d50"]
                available_input_cols = [c for c in input_cols if c in result_df.columns]
                measured_col = ["Gmax"] if "Gmax" in result_df.columns else []
                predicted_cols = [col for col in result_df.columns if col.startswith("Gmax_")]
                filtered_df = result_df[available_input_cols + measured_col + predicted_cols]

                st.dataframe(filtered_df, use_container_width=True)

                if "Gmax" in result_df.columns:
                    st.markdown("#### Statistical comparison")
                    st.dataframe(stats_df, use_container_width=True)

                    fig = plot_predicted_measured_all_models(
                        result_df,
                        selected_models,
                        {k: MODELS[k].display_name for k in selected_models},
                    )
                    if fig is not None:
                        st.markdown("#### Predicted-measured comparison")
                        st.pyplot(fig)

                excel_bytes = dataframe_to_excel_bytes(filtered_df, stats_df)
                st.download_button(
                    "Download prediction results (Excel)",
                    data=excel_bytes,
                    file_name="gmax_empirical_predictions.xlsx",
                    mime="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
                )

        except Exception as exc:
            st.error(f"Could not read or process the uploaded file: {exc}")
